(2626, 'Physiotherapy for Critical Care Nursing', 'PHY213.04 Objectives', 'Early mobilization should be stopped when the following parameters are as below, except:', '["HR < 40 OR > 130bpm", "RR < 5 OR >35 cpm", "SPO2 < 88% FOR < 1", "SBP > 90 mm Hg OR < 180 mm Hg"]'::jsonb, 3, '', 'Rehabilitation & Mobilization', '🏃', true),
(2627, 'Physiotherapy for Critical Care Nursing', 'PHY213.04 Objectives', 'An example of technique for airways clearance and lung inflation is:', '["Diaphragmatic breathing", "manual hyperinflation", "Pursed lip breathing", "Inspiratory muscle training"]'::jsonb, 1, '', 'Rehabilitation & Mobilization', '🏃', true),
(2628, 'Physiotherapy for Critical Care Nursing', 'PHY213.04 Objectives', 'Which of The following is NOT a barrier to early mobilization in ICU?', '["Co- morbidities", "Physiologic Instability", "ICU environment", "Gender"]'::jsonb, 3, '', 'Rehabilitation & Mobilization', '🏃', true),
(2629, 'Physiotherapy for Critical Care Nursing', 'PHY213.04 Objectives', 'When initiating an early mobilization protocol for mechanically ventilated patients the following parameters need to be as below, except:', '["HR < 130 bpm", "MAP 60-100mm Hg", "FiO2 < 60 %", "SPO2 < 88%"]'::jsonb, 3, '', 'Rehabilitation & Mobilization', '🏃', true),
