(2632, 'Physiotherapy for Critical Care Nursing', 'PHY213.04 Objectives', 'Effective mucous clearance may be hindered in critically ill patient by:', '["Presence of a tracheal tube", "Postural Drainage", "Therapeutic Positioning", "Used of other life supporting device"]'::jsonb, 0, '', 'Rehabilitation & Mobilization', '🏃', true),
(2633, 'Physiotherapy for Critical Care Nursing', 'PHY213.04 Objectives', 'Which of the following is NOT metabolic consequence of immobilization?', '["Fluid and electrolyte changes", "Bone demineralization", "Altered gastrointestinal function", "Hyper tonicity"]'::jsonb, 3, '', 'Rehabilitation & Mobilization', '🏃', true),
