(2636, 'Physiotherapy for Critical Care Nursing', 'PHY213.04 Objectives', 'Which of the following is NOT risk factor associated with venous thrombosis following immobilization?', '["Hyper coagulobility", "Vascular stasis", "Vessels trauma", "Ankle pump"]'::jsonb, 3, '', 'Rehabilitation & Mobilization', '🏃', true),
