(2641, 'Physiotherapy for Critical Care Nursing', 'PHY213.04 Objectives', 'Physiotherapy is a health care profession primarily concern with the following except:', '["Remediation of impairment and disability", "Promotion of mobility", "Improvement of quality of life and movement potential", "Promotion of morbidity and mortality"]'::jsonb, 3, '', 'Rehabilitation & Mobilization', '🏃', true),
