(2644, 'Physiotherapy for Critical Care Nursing', 'PHY213.04 Objectives', 'Which of the following is NOT type of Stretching exercise?', '["Static stretching", "Ballistic stretching", "Dynamic stretching", "Eccentric stretching"]'::jsonb, 3, '', 'Rehabilitation & Mobilization', '🏃', true),
