(2649, 'Physiotherapy for Critical Care Nursing', 'PHY213.04 Objectives', 'Air moves to the lungs through the following except:', '["Nostrils", "Nasal cavity", "Sinuses", "Pharynx"]'::jsonb, 2, '', 'Rehabilitation & Mobilization', '🏃', true),
(2650, 'Physiotherapy for Critical Care Nursing', 'PHY213.04 Objectives', 'The total lung volume (TLV) comprises of the following except:', '["Vital capacity", "Expiratory reserve volume", "Tidal volume", "force expiration"]'::jsonb, 3, '', 'Rehabilitation & Mobilization', '🏃', true),
