(2703, 'Post-Operative Complications', 'ICU Self Assessment Practice Session', 'Kidney failure is a potential postoperative complication in the ICU. Which laboratory test would be most indicative of kidney function?', '["Glucose levels", "Potassium levels", "Creatinine levels", "Sodium levels"]'::jsonb, 2, '', 'Mixed Revision', '📚', true),
