(2706, 'Post-Operative Complications', 'ICU Self Assessment Practice Session', 'Delayed wound healing is a common postoperative complication. Which factor can contribute to impaired wound healing?', '["High protein diet", "Smoking", "Regular wound dressing changes", "Adequate hydration"]'::jsonb, 1, '', 'Mixed Revision', '📚', true),
(2707, 'Post-Operative Complications', 'ICU Self Assessment Practice Session', 'A patient in the ICU develops urinary retention as a postoperative complication. Which intervention should the nurse implement to address thisissue?', '["Encourage the patient to drink plenty of fluids", "Insert a urinary catheter", "Administer diuretic medications", "Encourage frequent ambulation"]'::jsonb, 1, '', 'Mixed Revision', '📚', true),
(2708, 'Post-Operative Complications', 'ICU Self Assessment Practice Session', 'Paralytic ileus is a potential complication in the postoperative period. What symptom would the nurse expect to assess in a patient with paralytic ileus?', '["Diarrhea", "Abdominal distention", "Constipation", "Increased bowel sounds"]'::jsonb, 1, '', 'Mixed Revision', '📚', true),
(2709, 'Post-Operative Complications', 'ICU Self Assessment Practice Session', 'Adhesion formation can occur as a postoperative complication. What imaging study may be ordered to diagnose adhesions?', '["MRI", "CT scan", "X-ray", "Ultrasound"]'::jsonb, 0, '', 'Mixed Revision', '📚', true),
(2710, 'Post-Operative Complications', 'ICU Self Assessment Practice Session', 'A patient in the ICU develops a seroma postoperatively. What intervention should the nurse implement to manage the seroma?', '["Apply warm compresses to the affected area", "Administer antibiotics", "Drain the seroma with a needle", "Encourage the patient to elevate the affected limb"]'::jsonb, 2, '', 'Mixed Revision', '📚', true),
(2711, 'Post-Operative Complications', 'ICU Self Assessment Practice Session', 'Hematoma formation is a potential complication in the postoperative period. What assessment finding would indicate the presence of a hematoma?', '["Redness and warmth at the incision site", "Palpable swelling and bruising", "Purulent drainage from the wound", "Delayed wound healing"]'::jsonb, 1, '', 'Mixed Revision', '📚', true),
